#include <stdio.h>
#include <limits.h>
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long minVal = LLONG_MAX;
        for (int i = 0; i < N; ++i) {
            long long x; scanf("%lld", &x);
            if (x < minVal) minVal = x;
        }
        long long ans = (long long)N * minVal;
        printf("%lld\n", ans);
    }
    return 0;
}

