import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        min_val = 10**18
        for _ in range(N):
            x = int(next(it))
            if x < min_val:
                min_val = x
        out_lines.append(str(N * min_val))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

